using System.Linq;

public sealed class CustomMigrationsGenerator : CSharpMigrationsGenerator
{

    public CustomMigrationsGenerator(MigrationsCodeGeneratorDependencies deps, CSharpMigrationsGeneratorDependencies csharpDeps) : base(deps, csharpDeps) { }

    public override string GenerateMigration(string migrationNamespace, string migrationName, IReadOnlyList<MigrationOperation> upOperations, IReadOnlyList<MigrationOperation> downOperations)
    {

        var clearCacheOperation = new SqlOperation
        {
            Sql = "ALTER DATABASE SCOPED CONFIGURATION CLEAR PROCEDURE_CACHE;",
            SuppressTransaction = true
        };

        return base.GenerateMigration(migrationNamespace, migrationName, upOperations.Concat(new[] { clearCacheOperation }).ToList(), downOperations);

