await using var context = new ApplicationDbContext();
await context.Database.EnsureDeletedAsync();
await context.Database.EnsureCreatedAsync();

Func<ApplicationDbContext, string[], IAsyncEnumerable<Currency>> func
    = EF.CompileAsyncQuery((ApplicationDbContext context, string[] search) => context.Currencies.Where(e => search.Any()));

_ = await func(context, []).ToListAsync();

// Non-compiled version works:
// string[] search = [];
// _ = await context.Currencies.Where(e => search.Any()).ToListAsync();

public class ApplicationDbContext : DbContext
{
    public DbSet<Currency> Currencies { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
        => optionsBuilder
            .UseSqlServer(Environment.GetEnvironmentVariable("Test__SqlServer__DefaultConnection"))
            .LogTo(Console.WriteLine, LogLevel.Information)
            .EnableSensitiveDataLogging();
}

public class Currency
{
    public int Id { get; set; }
    public string Name { get; set; }
}
