        builder.HasKey(t => t.Id);
		//other mappings

        builder.ComplexCollection(t => t.KolomMetadata, builder => builder.ToJson().Configure());
		//Note: the Configure() method sets the property names of the KolomMetadata to camelCase
	}
}


