    .AsNoTracking()
    .Where(p => p.Id == parentId)
    .Select(p => new ParentVm(
        p.Name,
        p.Children.Select(c => new ChildVm(new InnerVm(c.Data))).ToList(),  // collection nav + struct
        new OuterVm(p.Coords)                                               // nested struct
